import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/faq.md","filePath":"troubleshooting/faq.md"}'),s={name:"troubleshooting/faq.md"};function n(i,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="why-can-i-see-a-guide-in-the-docs-but-not-the-page-in-the-app" tabindex="-1">Why can I see a guide in the docs but not the page in the app? <a class="header-anchor" href="#why-can-i-see-a-guide-in-the-docs-but-not-the-page-in-the-app" aria-label="Permalink to &quot;Why can I see a guide in the docs but not the page in the app?&quot;">​</a></h2><p>Docs cover the whole platform, but your role only sees the parts allowed to it. Start with <a href="./../roles/overview.html">Roles Explained</a> and <a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a>.</p><h2 id="why-is-the-kingdom-analytics-tab-missing-for-my-alliance-leader-account" tabindex="-1">Why is the Kingdom analytics tab missing for my Alliance Leader account? <a class="header-anchor" href="#why-is-the-kingdom-analytics-tab-missing-for-my-alliance-leader-account" aria-label="Permalink to &quot;Why is the Kingdom analytics tab missing for my Alliance Leader account?&quot;">​</a></h2><p>Alliance leadership does not get that tab from kingdom membership alone. It appears only through an <strong>accepted</strong> kingdom grant carrying the kingdom analytics feature. See <a href="./../analytics/kingdom.html">Kingdom Analytics</a>.</p><h2 id="why-did-my-screenshot-import-create-no-live-data" tabindex="-1">Why did my screenshot import create no live data? <a class="header-anchor" href="#why-did-my-screenshot-import-create-no-live-data" aria-label="Permalink to &quot;Why did my screenshot import create no live data?&quot;">​</a></h2><p>Because upload is review-first. Live data is only written when rows are accepted. See <a href="./../imports/overview.html">How Screenshot Imports Work</a>.</p><h2 id="why-did-the-app-warn-me-before-overwriting-a-result" tabindex="-1">Why did the app warn me before overwriting a result? <a class="header-anchor" href="#why-did-the-app-warn-me-before-overwriting-a-result" aria-label="Permalink to &quot;Why did the app warn me before overwriting a result?&quot;">​</a></h2><p>That row was a <code>conflict</code>, meaning a result already exists for that player and event context. The overwrite warning is expected. See <a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a>.</p><h2 id="why-did-rollback-not-restore-every-single-old-value" tabindex="-1">Why did rollback not restore every single old value? <a class="header-anchor" href="#why-did-rollback-not-restore-every-single-old-value" aria-label="Permalink to &quot;Why did rollback not restore every single old value?&quot;">​</a></h2><p>Rollback is intentionally cautious. It skips pieces that were changed again later instead of erasing newer unrelated work. See <a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>.</p><h2 id="why-does-a-restored-import-not-instantly-bring-back-all-results" tabindex="-1">Why does a restored import not instantly bring back all results? <a class="header-anchor" href="#why-does-a-restored-import-not-instantly-bring-back-all-results" aria-label="Permalink to &quot;Why does a restored import not instantly bring back all results?&quot;">​</a></h2><p>Restore brings the import back as <code>restored_draft</code>, not as live data. You still review rows and accept them again if they are still correct. See <a href="./../imports/restore-import.html">Restore a Deleted Import</a>.</p><h2 id="why-can-i-not-add-results-even-though-the-event-still-exists" tabindex="-1">Why can I not add results even though the event still exists? <a class="header-anchor" href="#why-can-i-not-add-results-even-though-the-event-still-exists" aria-label="Permalink to &quot;Why can I not add results even though the event still exists?&quot;">​</a></h2><p>The instance may be locked after the 3-day cleanup window. Use <a href="./../how-to/session-lock.html">Locked Instances &amp; Unlock Requests</a>.</p><h2 id="why-did-adding-one-more-player-suddenly-fail" tabindex="-1">Why did adding one more player suddenly fail? <a class="header-anchor" href="#why-did-adding-one-more-player-suddenly-fail" aria-label="Permalink to &quot;Why did adding one more player suddenly fail?&quot;">​</a></h2><p>You likely hit a player quota or another hard resource limit. Check the usage panel and <a href="./quotas.html">Quota &amp; Suspension Problems</a>.</p><h2 id="why-can-cleanup-still-run-when-everything-else-is-blocked" tabindex="-1">Why can cleanup still run when everything else is blocked? <a class="header-anchor" href="#why-can-cleanup-still-run-when-everything-else-is-blocked" aria-label="Permalink to &quot;Why can cleanup still run when everything else is blocked?&quot;">​</a></h2><p>That is how limited mode is designed. Read access and cleanup stay available so you can recover. See <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a>.</p><h2 id="why-does-alliance-brawl-ask-me-to-choose-a-stage" tabindex="-1">Why does Alliance Brawl ask me to choose a stage? <a class="header-anchor" href="#why-does-alliance-brawl-ask-me-to-choose-a-stage" aria-label="Permalink to &quot;Why does Alliance Brawl ask me to choose a stage?&quot;">​</a></h2><p>Because stage choice matters for that event and should not be guessed. Day screenshots must be imported with the correct stage selection. See <a href="./../events/alliance-brawl.html">Alliance Brawl</a>.</p><h2 id="why-is-sanctuary-battle-documented-differently-from-score-based-events" tabindex="-1">Why is Sanctuary Battle documented differently from score-based events? <a class="header-anchor" href="#why-is-sanctuary-battle-documented-differently-from-score-based-events" aria-label="Permalink to &quot;Why is Sanctuary Battle documented differently from score-based events?&quot;">​</a></h2><p>Because Sanctuary Battle is primarily a participation and control outcome event, not a normal score-first template. See <a href="./../events/sanctuary-battle.html">Sanctuary Battle</a>.</p><h2 id="why-can-a-king-not-delete-some-users-in-their-own-kingdom" tabindex="-1">Why can a King not delete some users in their own kingdom? <a class="header-anchor" href="#why-can-a-king-not-delete-some-users-in-their-own-kingdom" aria-label="Permalink to &quot;Why can a King not delete some users in their own kingdom?&quot;">​</a></h2><p>Kings are limited by the creator-ownership rule. Some users were not created by that King, or are protected for stronger reasons. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="why-can-i-request-a-restore-but-not-restore-directly" tabindex="-1">Why can I request a restore but not restore directly? <a class="header-anchor" href="#why-can-i-request-a-restore-but-not-restore-directly" aria-label="Permalink to &quot;Why can I request a restore but not restore directly?&quot;">​</a></h2><p>Your role can see the deleted item but does not have direct restore permission. That is exactly what the restore-request flow is for. See <a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a>.</p><h2 id="why-does-the-plan-editor-show-prices-if-the-app-does-not-bill-me" tabindex="-1">Why does the plan editor show prices if the app does not bill me? <a class="header-anchor" href="#why-does-the-plan-editor-show-prices-if-the-app-does-not-bill-me" aria-label="Permalink to &quot;Why does the plan editor show prices if the app does not bill me?&quot;">​</a></h2><p>Those fields are display-only. Payment still happens manually through the request thread and support links. See <a href="./../admin/manage-plans.html">Create &amp; Edit Plans</a> and <a href="./../subscriptions/payment-instructions.html">Payment Instructions &amp; Completing a Request</a>.</p><h2 id="why-can-a-directly-subscribed-alliance-survive-a-kingdom-usage-limit-suspension" tabindex="-1">Why can a directly subscribed alliance survive a kingdom usage-limit suspension? <a class="header-anchor" href="#why-can-a-directly-subscribed-alliance-survive-a-kingdom-usage-limit-suspension" aria-label="Permalink to &quot;Why can a directly subscribed alliance survive a kingdom usage-limit suspension?&quot;">​</a></h2><p>That is part of the subscription hierarchy and suspension rules. See <a href="./../subscriptions/direct-alliance-subscription.html">Direct Alliance Subscriptions</a> and <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a>.</p>',31)])])}const m=a(s,[["render",n]]);export{p as __pageData,m as default};
